import re, pathlib
p = pathlib.Path('/Users/gbang/Downloads/algora/workspace/3337c073-c8e8-49f2-965c-6946df2d6765_hld/_response.md')
md = p.read_text()
blocks = re.findall(r'```mermaid(.*?)```', md, re.S)
# Check actual node defs Name[...] / Name[(...)] / Name[[...]] for breaking chars in the inner text
issues=[]
for i,b in enumerate(blocks):
    for line in b.splitlines():
        line=line.strip()
        if line.startswith('subgraph'):  # quoted titles fine
            continue
        # node label content
        for m in re.finditer(r'[A-Za-z0-9_]+(\[\[|\[\(|\[)([^\]\)]*)', line):
            inner=m.group(2)
            for c in ['(',')',':','/','<','>',';','{','}','|']:
                if c in inner: issues.append((i,'NODE',inner,c,line))
        # edge labels |"..."| or |...|
        for m in re.finditer(r'\|"?([^"|]+?)"?\|', line):
            inner=m.group(1)
            for c in ['(',')',':','/','<','>',';','{','}']:
                if c in inner: issues.append((i,'EDGE',inner,c,line))
print("REAL issues:", issues if issues else "NONE — all node/edge labels clean")
# also: confirm classDef lines (which contain : and ;) are fine — they're directives, not labels
